#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 1e5+5;
struct line{int u,v,w,col;}ln[N];
int n,m,need,l,r,fa[N],Ans,wadd,cnt,bqh;
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
bool cmp(line l1,line l2){
    return (l1.w<l2.w)||(l1.w==l2.w&&l1.col>l2.col);
}
int FF(int u){return (fa[u]==u?u:fa[u]=FF(fa[u]));}
void Merge(int u,int v){u=FF(u),v=FF(v),fa[v]=u;return;}
void Kruskal_sol_MST(){
    sort(ln+1,ln+m+1,cmp);
    for(int i=1;i<=n;i++)fa[i]=i;
    cnt=0,bqh=0;
    for(int i=1;i<=m;i++){
        auto [u,v,w,col]=ln[i];
        if(FF(u)==FF(v))continue;
        Merge(u,v),cnt+=col,bqh+=w;
    }return;
}
bool check(int add){
    for(int i=1;i<=m;i++)
        if(ln[i].col)ln[i].w+=add;
    Kruskal_sol_MST();
    for(int i=1;i<=m;i++)
        if(ln[i].col)ln[i].w-=add;
    return (cnt>=need);
}
int main(){
    n=read(),m=read(),need=read();
    for(int i=1;i<=m;i++)
        ln[i].u=read()+1,ln[i].v=read()+1,
        ln[i].w=read(),ln[i].col=1-read();
    l=-100,r=100,wadd=0;
    while(l<=r){
        int mid=(l+r)/2;
        if(check(mid))wadd=mid,l=mid+1;
        else r=mid-1;
    }check(wadd);
    cout<<bqh-wadd*need<<"\n";
    return 0;
}
